'use client'
import {
  cn,
  createMachine,
  useMachine,
  useSignal,
  useSignalEffect,
  useSignals,
} from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { useId, useRef, type KeyboardEvent } from 'react'
import styles from './combobox.module.css'

const machine = createMachine({
  initial: 'closed' as const,
  states: {
    closed: { on: { OPEN: 'open' } },
    open: { on: { CLOSE: 'closed' } },
  },
})

export interface ComboboxOption {
  value: string
  label: string
  disabled?: boolean
}

export interface ComboboxLabels {
  placeholder?: string
  empty?: string
  clear?: string
  search?: string
}

export interface ComboboxProps {
  options: ComboboxOption[]
  value?: string
  defaultValue?: string
  onChange?: (value: string | undefined) => void
  clearable?: boolean
  searchable?: boolean
  label?: string
  hint?: string
  error?: string
  size?: 'sm' | 'md' | 'lg'
  disabled?: boolean
  labels?: ComboboxLabels
  className?: string
  id?: string
}

export function Combobox({
  options,
  value,
  defaultValue,
  onChange,
  clearable = false,
  searchable = true,
  label,
  hint,
  error,
  size = 'md',
  disabled = false,
  labels,
  className,
  id,
}: ComboboxProps) {
  useSignals()
  const [state, send] = useMachine(machine)
  const baseId = useId()
  const inputId = id ?? (label ? `cascade-combobox-${baseId}` : `cascade-combobox-${baseId}`)
  const listboxId = `${baseId}-listbox`
  const inputRef = useRef<HTMLInputElement>(null)
  const resolvedPlaceholder = labels?.placeholder ?? t(builtin.combobox.placeholder)
  const resolvedEmpty = labels?.empty ?? t(builtin.combobox.empty)
  const resolvedClear = labels?.clear ?? t(builtin.combobox.clear)
  const resolvedSearch = labels?.search ?? t(builtin.combobox.search)

  // Controlled vs. uncontrolled selected value
  const selectedSignal = useSignal<string | undefined>(value ?? defaultValue)
  if (value !== undefined) selectedSignal.value = value

  const query = useSignal('')
  const activeIndex = useSignal(0)

  const isOpen = state.value === 'open'

  const filtered = options.filter((opt) => {
    if (!searchable || !query.value) return true
    return opt.label.toLowerCase().includes(query.value.toLowerCase())
  })

  const selectedOption = options.find((opt) => opt.value === selectedSignal.value)

  // Close on outside click
  useSignalEffect(() => {
    if (!isOpen) return
    const handler = (e: MouseEvent) => {
      const root = document.getElementById(`${baseId}-root`)
      if (root && !root.contains(e.target as Node)) send('CLOSE')
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  })

  const open = () => {
    if (disabled) return
    query.value = ''
    activeIndex.value = 0
    send('OPEN')
    setTimeout(() => inputRef.current?.focus(), 0)
  }

  const close = () => {
    send('CLOSE')
    query.value = ''
  }

  const select = (optValue: string) => {
    if (value === undefined) selectedSignal.value = optValue
    onChange?.(optValue)
    close()
  }

  const clear = () => {
    if (value === undefined) selectedSignal.value = undefined
    onChange?.(undefined)
  }

  const enabledIndexes = filtered.flatMap((opt, i) => (opt.disabled ? [] : [i]))

  const moveActive = (delta: number) => {
    if (enabledIndexes.length === 0) return
    const pos = enabledIndexes.indexOf(activeIndex.value)
    const next = enabledIndexes[(pos + delta + enabledIndexes.length) % enabledIndexes.length]
    if (next !== undefined) activeIndex.value = next
  }

  const handleTriggerKeyDown = (e: KeyboardEvent<HTMLButtonElement>) => {
    if (e.key === 'Enter' || e.key === ' ' || e.key === 'ArrowDown') {
      e.preventDefault()
      open()
    }
  }

  const handleInputKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault()
        moveActive(1)
        break
      case 'ArrowUp':
        e.preventDefault()
        moveActive(-1)
        break
      case 'Enter': {
        e.preventDefault()
        const opt = filtered[activeIndex.value]
        if (opt && !opt.disabled) select(opt.value)
        break
      }
      case 'Escape':
        e.preventDefault()
        close()
        break
      case 'Tab':
        close()
        break
    }
  }

  const optionId = (i: number) => `${baseId}-option-${i}`

  return (
    <div
      id={`${baseId}-root`}
      className={cn(styles['wrapper'], className)}
      data-state={error ? 'error' : state.value}
      data-size={size}
    >
      {label && (
        <label className={styles['label']} htmlFor={inputId}>
          {label}
        </label>
      )}
      <div className={styles['field']}>
        <button
          id={inputId}
          type="button"
          role="combobox"
          aria-expanded={isOpen}
          aria-controls={listboxId}
          aria-haspopup="listbox"
          aria-activedescendant={
            isOpen && activeIndex.value >= 0 ? optionId(activeIndex.value) : undefined
          }
          aria-invalid={error ? true : undefined}
          aria-describedby={error ? `${baseId}-error` : hint ? `${baseId}-hint` : undefined}
          className={styles['trigger']}
          disabled={disabled}
          onKeyDown={handleTriggerKeyDown}
          onClick={isOpen ? close : open}
        >
          <span
            className={cn(styles['value'], !selectedOption ? styles['placeholder'] : undefined)}
          >
            {selectedOption?.label ?? resolvedPlaceholder}
          </span>
          <span className={styles['chevron']} aria-hidden="true" />
        </button>
        {clearable && selectedSignal.value !== undefined && (
          <button
            type="button"
            className={styles['clear']}
            aria-label={resolvedClear}
            onClick={(e) => {
              e.stopPropagation()
              clear()
            }}
          >
            ✕
          </button>
        )}
      </div>
      <div
        role="listbox"
        id={listboxId}
        className={styles['listbox']}
        data-state={isOpen ? 'open' : 'closed'}
        aria-label={label}
      >
        {searchable && isOpen && (
          <div className={styles['searchWrapper']}>
            <input
              ref={inputRef}
              type="text"
              className={styles['search']}
              value={query.value}
              onChange={(e) => {
                query.value = e.target.value
                activeIndex.value = 0
              }}
              onKeyDown={handleInputKeyDown}
              aria-label={resolvedSearch}
              autoComplete="off"
            />
          </div>
        )}
        {filtered.length === 0 ? (
          <div className={styles['empty']}>{resolvedEmpty}</div>
        ) : (
          filtered.map((opt, i) => (
            <div
              key={opt.value}
              id={optionId(i)}
              role="option"
              aria-selected={opt.value === selectedSignal.value}
              aria-disabled={opt.disabled || undefined}
              data-state={i === activeIndex.value ? 'active' : undefined}
              data-disabled={opt.disabled || undefined}
              className={styles['option']}
              onMouseEnter={() => {
                if (!opt.disabled) activeIndex.value = i
              }}
              onClick={() => {
                if (!opt.disabled) select(opt.value)
              }}
            >
              {opt.label}
            </div>
          ))
        )}
      </div>
      {error && (
        <span id={`${baseId}-error`} className={styles['error']} role="alert">
          {error}
        </span>
      )}
      {!error && hint && (
        <span id={`${baseId}-hint`} className={styles['hint']}>
          {hint}
        </span>
      )}
    </div>
  )
}

@layer cascivo.component {
  .wrapper {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
    font-family: var(--cascivo-font-sans);
    position: relative;
  }

  .label {
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text);
  }

  .field {
    position: relative;
    display: flex;
    align-items: center;
  }

  .trigger {
    display: flex;
    align-items: center;
    justify-content: space-between;
    inline-size: 100%;
    padding-inline: var(--cascivo-space-3);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    background-color: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-field);
    cursor: pointer;
    outline: none;
    text-align: start;
    transition:
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover:not(:disabled) {
      border-color: var(--cascivo-color-border-strong);
    }

    &:focus-visible {
      border-color: var(--cascivo-color-accent);
      box-shadow: 0 0 0 3px color-mix(in srgb, var(--cascivo-color-accent) 20%, transparent);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }

  .wrapper[data-size='sm'] .trigger {
    block-size: 2rem;
  }
  .wrapper[data-size='md'] .trigger {
    block-size: 2.5rem;
  }
  .wrapper[data-size='lg'] .trigger {
    block-size: 3rem;
  }

  .wrapper[data-state='error'] .trigger {
    border-color: var(--cascivo-color-danger);
  }

  .value {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .placeholder {
    color: var(--cascivo-color-text-subtle);
  }

  .chevron {
    display: inline-block;
    inline-size: 0.75rem;
    block-size: 0.75rem;
    border-inline-end: 2px solid var(--cascivo-color-text-muted);
    border-block-end: 2px solid var(--cascivo-color-text-muted);
    transform: rotate(45deg);
    flex-shrink: 0;
    margin-inline-start: var(--cascivo-space-2);
    transition: transform var(--cascivo-duration-150) var(--cascivo-ease-out);
  }

  .wrapper[data-state='open'] .chevron {
    transform: rotate(-135deg);
  }

  .clear {
    position: absolute;
    inset-inline-end: var(--cascivo-space-8);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-block-size: 1.5rem; /* 24px — WCAG 2.5.8 target size */
    min-inline-size: 1.5rem;
    background: none;
    border: none;
    cursor: pointer;
    color: var(--cascivo-color-text-muted);
    font-size: var(--cascivo-text-xs);
    padding: var(--cascivo-space-1);
    outline: none;
    border-radius: var(--cascivo-radius-control);

    &:hover {
      color: var(--cascivo-color-text);
    }
    &:focus-visible {
      box-shadow: 0 0 0 2px var(--cascivo-color-accent);
    }
  }

  /* Listbox with @starting-style enter animation */
  .listbox {
    position: absolute;
    inset-block-start: calc(100% + var(--cascivo-space-1));
    inset-inline-start: 0;
    inline-size: 100%;
    z-index: var(--cascivo-z-dropdown);
    max-block-size: 16rem;
    overflow-y: auto;
    background-color: var(--cascivo-color-surface-overlay);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-overlay);
    opacity: 0;
    visibility: hidden;
    translate: 0 -0.25rem;
    transition:
      opacity var(--cascivo-motion-enter),
      translate var(--cascivo-motion-enter),
      visibility var(--cascivo-motion-enter);

    &[data-state='open'] {
      opacity: 1;
      visibility: visible;
      translate: 0 0;
    }

    @starting-style {
      &[data-state='open'] {
        opacity: 0;
        translate: 0 -0.25rem;
      }
    }
  }

  .searchWrapper {
    padding: var(--cascivo-space-2);
    border-block-end: 1px solid var(--cascivo-color-border);
  }

  .search {
    inline-size: 100%;
    padding-inline: var(--cascivo-space-2);
    padding-block: var(--cascivo-space-1);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    background-color: var(--cascivo-color-bg-subtle);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-field);
    outline: none;

    &:focus-visible {
      border-color: var(--cascivo-color-accent);
    }
  }

  .option {
    padding-inline: var(--cascivo-space-3);
    padding-block: var(--cascivo-space-2);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    cursor: pointer;
    border-radius: var(--cascivo-radius-item);

    &[data-state='active'] {
      background-color: var(--cascivo-color-bg-subtle);
    }

    &[aria-selected='true'] {
      background-color: color-mix(in srgb, var(--cascivo-color-accent) 12%, transparent);
      color: var(--cascivo-color-accent);
    }

    &[data-disabled] {
      opacity: 0.4;
      cursor: not-allowed;
    }
  }

  .empty {
    padding: var(--cascivo-space-4);
    text-align: center;
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-muted);
  }

  .error {
    font-size: var(--cascivo-text-xs);
    color: var(--cascivo-color-danger);
  }

  .hint {
    font-size: var(--cascivo-text-xs);
    color: var(--cascivo-color-text-muted);
  }
}
